#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld",&N);
        if(N==2){
            printf("NO\n");
            continue;
        }
        printf("YES\n");
        long long k = ceil(sqrt((double)N));
        long long cur=1;
        while(cur<=N){
            long long end = cur + k - 1;
            if(end> N) end = N;
            for(long long x=end; x>=cur; --x){
                printf("%lld", x);
                if(x>cur) printf(" ");
            }
            if(end<N) printf(" ");
            cur = end + 1;
        }
        printf("\n");
    }
    return 0;
}

