#!/usr/bin/env python3
import sys, math

def solve():
    it = iter(sys.stdin.read().strip().split())
    t = int(next(it))
    out = []
    for _ in range(t):
        n = int(next(it))
        if n == 2:
            out.append("NO")
            continue
        out.append("YES")
        k = math.isqrt(n)
        if k * k < n:
            k += 1
        perm = []
        start = 1
        while start <= n:
            end = min(start + k - 1, n)
            perm.extend(range(end, start - 1, -1))
            start = end + 1
        out.append(' '.join(map(str, perm)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

